import React, { useState, useEffect } from 'react';

function TestimonialCarousel() {
  const testimonials = [
    {
      id: 1,
      text: 'Lorem ipsum dolor sit amet, consectetur adipiscing elit. Sed sit amet nulla auctor, vestibulum magna sed, convallis ex.',
      author: 'John Doe',
    },
    {
      id: 2,
      text: 'Lorem ipsum dolor sit amet, consectetur adipiscing elit. Sed sit amet nulla auctor, vestibulum magna sed, convallis ex.',
      author: 'Jane Doe',
    },
    {
      id: 3,
      text: 'Lorem ipsum dolor sit amet, consectetur adipiscing elit. Sed sit amet nulla auctor, vestibulum magna sed, convallis ex.',
      author: 'Bob Smith',
    },
  ];

  const [activeTestimonial, setActiveTestimonial] = useState(0);

  useEffect(() => {
    const intervalId = setInterval(() => {
      setActiveTestimonial((prevActiveTestimonial) => (prevActiveTestimonial + 1) % testimonials.length);
    }, 5000);

    return () => clearInterval(intervalId);
  }, [testimonials.length]);

  return (
    <section
      className="bg-[#F8FAFC] py-12 md:py-16 lg:py-20 xl:py-24"
      aria-label="Testimonials Section"
    >
      <div className="container mx-auto flex flex-col items-center justify-center gap-12 md:gap-16 lg:gap-20 xl:gap-24">
        <h2
          className="text-3xl md:text-5xl lg:text-7xl font-bold text-[#6C5CE7] transition-all duration-500"
          style={{
            textShadow: '0px 4px 4px rgba(0, 0, 0, 0.25)',
          }}
        >
          What Our Customers Say
        </h2>
        <div className="flex flex-col items-center justify-center gap-8 md:gap-12 lg:gap-16 xl:gap-20">
          {testimonials.map((testimonial, index) => (
            <div
              key={testimonial.id}
              className={`${
                activeTestimonial === index
                  ? 'opacity-100 scale-100'
                  : 'opacity-50 scale-90'
              } transition-all duration-500 rounded-4xl bg-[#FFFFFF] p-8 md:p-12 lg:p-16 xl:p-20 shadow-lg shadow-[#A29BFE]`}
            >
              <p
                className="text-2xl md:text-3xl lg:text-5xl text-[#6C5CE7] font-inter text-center"
                style={{
                  textShadow: '0px 4px 4px rgba(0, 0, 0, 0.25)',
                }}
              >
                {testimonial.text}
              </p>
              <p
                className="text-lg md:text-xl lg:text-2xl text-[#A29BFE] font-inter text-center mt-4 md:mt-6 lg:mt-8 xl:mt-10"
                style={{
                  textShadow: '0px 4px 4px rgba(0, 0, 0, 0.25)',
                }}
              >
                - {testimonial.author}
              </p>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

export default TestimonialCarousel;

